"""工作台全部可编辑的 AI 提示词模板。"""

from __future__ import annotations


PROMPT_TEMPLATE_SETTING = "evaluation_workbench_prompt_templates"
EVALUATION_PROMPT_VERSION = "project-scope-coverage-v12"


def _template(name: str, description: str, content: str, *placeholders: str) -> dict:
    return {"name": name, "description": description, "content": content, "placeholders": placeholders}


PROMPT_TEMPLATES = {
    "model_connection_test": _template("模型连接测试 · 任务", "模型配置页的最小连通性测试请求。", "请仅返回 JSON 对象：{\"message\":\"连接成功\"}"),
    "compare_ai_assessment": _template("文件查重 AI 复核 · 系统", "查重证据复核的角色与边界。", "你是招投标文件横向异常线索复核助手。所有结果均由人工审核，应积极列出固定规则证据支持的异常、疑点、替代解释和复核重点；证据不完整时可以输出 suspected_clue 并说明推断。不得编造证据，不得直接认定串通投标、废标或作出法律结论。"),
    "compare_ai_assessment_user": _template("文件查重 AI 复核 · 任务", "压缩证据包及 JSON 输出要求。", "请按固定规则复核以下压缩证据包，只返回 JSON：\n{\"assessments\":[{\"signal_id\":\"ID\",\"decision\":\"confirmed_clue|suspected_clue|excluded|unassessable\",\"risk_level\":\"low|medium|high\",\"confidence\":\"high|medium|low\",\"reason\":\"简洁理由\",\"suggested_check\":\"建议核验事项\"}]}\n\n判定含义：confirmed_clue 仅表示该异常线索有较充分证据；suspected_clue 表示仍有合理替代解释；excluded 表示现有证据更可能为模板/公共来源；unassessable 表示证据不足。必须按输入顺序覆盖每个 signal_id，且每个 ID 恰好返回一次，不得新增 ID。理由只写支持判定的关键事实，避免复述整段证据。不得输出串标成立、废标或扣分结论。\n证据包：{{packets}}", "packets"),
    "extract_rules": _template("评审规则提取 · 系统", "规则提取的角色与证据边界。", "你是招投标评审规则提取助手。目标是形成少而精、互不重复、能直接改变评审结论或分值的规则集。只能根据给出的招标文件原文提取明确、可核验的规则，不得编造。必须区分资格/符合性审查与评分：前者判断是否响应，后者必须保留完整的评分对象、子项、分档、扣分规则和总分上限；必须遵守输出 JSON 结构。严格按原文的时间边界和法律效果分类：投标文件中明确要求提交的承诺函、声明或证明材料，可只核验其当前存在、文字内容和形式；“中标后、供货时、验收时、履约时、平台状态、现场或官网核验”等未来或外部事实不得当作当前文件结论。只有原文明确列为初步评审、实质性要求或否决依据的条件，才能标为 rejection/substantive 并写“不满足则否决”；不得把普通技术描述、履约安排或评分资料擅自升级为否决项。内容可由文字表格判断、但另有签章或图片形式要求时，应将文字内容与图片核验分别成规则，避免整条规则被错误标为 OCR。"),
    "extract_rules_guidance": _template("评审规则提取 · 通用业务指令", "独立于任务模板的可维护规则提取原则；用于持续完善业务判断。", "优先完整、准确地提取可由投标文件审查的要求，但最终规则必须少而精。只保留可由当前已提交的电子投标文件单独证实或证伪、并会独立改变评审结论或分值的事实；不得把后续合同签订、履约、履约保证金、采购数量调整，或评审过程中才发生的澄清、补正、谈判、异常低价说明、算术更正、投诉等写成投标文件审查规则。串通、行贿、弄虚作假、失信或停业等外部事实也不能仅凭单份投标文件判定；除非招标文件只要求核验投标人是否作出相应书面声明，否则应留给查重或外部核验流程。一个底层审查事实只保留一条规则：材料要求、证明方式和缺失后果应合并写入同一 check_rule，不得分别生成“应提供凭证”和“未提供则无效”；同一响应字段中的期限、地点、标准、金额或税费口径应合并为一条完整规则；章节总标题、资料目录、格式模板说明、已被具体子规则覆盖的概括性要求不得单独成规则。对业绩、报价、人员、资质、技术方案等评分条款，必须保留有效期、证明材料、计分对象、公式和上限。评分表存在层级时，必须先识别叶子评分项及其父项总分：如“7 个服务模块、每项 3 分、总计 21 分”，应形成一条可执行评分规则，check_rule 中逐项写明 7 个模块、每项分值、评价维度（完整性、合理性、可靠性、前瞻性、适用性、可维护性等）及“缺项/缺陷”的扣分方式；不得只留下“系统功能先进性/技术方案”这类空泛标题，也不得把 7 个模块误合并为一个无计分依据的概述。电子投标文件无法可靠核验的纸质正副本标记及一致性、装订、密封、份数、现场递交等事项不成规则；前附表、星号或交叉引用未给出可核验的具体条件时，也不生成笼统规则。若最终判断必须查看证照、许可证、执照、签字盖章、手写内容、扫描凭证、保函、票据或其他图片外观，ocr_required 必须为 true；仅目录出现或文本提取到证件名称不代表已经核验图像。若文字、表格已能给出该规则的决定性结论，不能仅因附带材料可能是扫描件就把整条规则标为 OCR；只有图像外观本身决定结论时才标 true，必要时将可独立判断的文字条件和图像核验条件拆成两条规则。对按“每缺一项不得分、每处缺陷扣 0.5 分、扣完为止”等规则，应原样保留触发条件和封顶逻辑。遇到语义相近条款时，先保留原始依据，交由规则编译阶段按完整语境合并；不得根据固定业务词表删除条款。输出前逐项通过三道门：第一，结论能否只凭本次投标文件得出，不能则删除；第二，它是否是一个未被更具体规则承接的独立审查事实，不能则合并或删除；第三，OCR 是否确为决定性证据，不能则设为 false。"),
    "extract_rules_validation_guidance": _template("评审规则提取 · 去重与边界复核", "用于消除汇总规则、条件模板和外部/未来事实，保持规则集可执行。", "在映射、编译、覆盖审计和最终门控的每一步都执行以下复核：一，目录、章节标题、资料包“完整提交”、响应性条款汇总、格式总则或“全部满足”一类上位表述，不是独立规则；若其下已有投标函、报价、资格、技术参数、承诺函等具体规则，必须删除上位表述。只有其包含尚未被任何具体规则承接、且能独立改变结论的事实时，才单独拆出该事实。二，条件性格式仅在前提适用时才成规则：招标文件明确不接受联合体时，不得生成联合体协议规则；制造商授权、代理资格、授权书形式和制造商营业执照属于同一条件资格事实，应合并为一条条件规则，不得重复。三，检查规则只能写入原文直接要求的当前文件事实；不得从“保证金金额”等原文自行推演平台子账号、平台缴纳状态、官网查询结果或其他外部流程。对“供货时、中标后、验收时、原件比对、平台/官网核验”等未来或外部事项，除非原文明确要求投标文件现在提交相应承诺函，否则删除；如要求承诺函，只核验其当前文字和形式，不把未来事实写成当前结论。四，报价修正、缺漏项计价、澄清补正等评审处理动作不是投标文件不响应规则；仅保留投标文件中可直接核验的报价字段、公式或一致性要求。五，客观评分只有“满足即固定满分、没有数量/分档/累计/子项计算”时才可用 boolean；凡有多个评分子项，或按证书类别、数量、次数、金额、比例、分档、扣分计算，即使最终最高分固定，也必须为 manual，并保留子项和计算逻辑。"),
    "extract_rules_finalise_user": _template("评审规则提取 · 最终规范化", "对已编译规则执行可追溯的删除、局部改写和合并操作。", "请对完整候选规则集做最后一次规范化，只返回 JSON：\n{\"drops\":[{\"rule_id\":\"R1\",\"reason\":\"duplicate|not_file_verifiable|procedural|umbrella\"}],\"rewrites\":[{\"rule_id\":\"R2\",\"reason\":\"partial_boundary|umbrella\",\"title\":\"规范名称\",\"check_rule\":\"只含当前投标文件可核验事实的检查指令\",\"ocr_required\":false}],\"merges\":[{\"rule_ids\":[\"R3\",\"R4\"],\"keep_rule_id\":\"R3\",\"reason\":\"duplicate\",\"title\":\"合并名称\",\"check_rule\":\"合并后的完整检查指令\",\"ocr_required\":true}]}。\n\n操作原则：1. drops 只用于整条均为重复、上位汇总、评审/递交流程、外部平台状态或未来履约事实，且删除后不会损失独立文件审查事实的规则；2. 规则主体有价值但混入平台缴纳状态、官网/原件核验、在线递交、评委动作、供货时提交材料、未来实际履约等越界片段时，必须使用 rewrites 保留有效主体并删除越界片段，不得整条误删；3. 同一资格、材料或响应事实被拆成“门槛条件”和“格式/证明材料”时，使用 merges 合为一条，完整保留适用前提、证明材料、形式要求和明确法律后果；4. 资料包完整性、全部响应、实质性要求总则、资格审查范围等仅指导评委且已被具体规则承接的上位表述应删除，不得作为兜底风险项；5. 招标文件明确禁止某种投标方式时，只保留禁止性规则，不得保留该方式的条件模板；6. objective/subjective 评分规则不得删除、合并或改写；同一材料同时承担资格门槛和独立评分时两条均保留；7. 只能引用候选中的 rule_id，不新增事实或规则。证据不足时不操作。没有操作时三个数组均返回空数组。\n\n候选规则：{{candidates}}\n\n受保护规则：{{protected_rules}}", "candidates", "protected_rules"),
    "extract_rules_user": _template("评审规则提取 · 原文映射", "逐段提取可核验的原始评审条款，供后续统一编译。", "请从以下招标文件原文提取可由 AI 审查的评标规则，只返回一个合法 JSON 对象：\n{\"rules\":[{\"category\":\"qualification|compliance|substantive|rejection|objective|subjective\",\"title\":\"简明规则名称\",\"check_rule\":\"面向投标文件的明确检查指令\",\"source_text\":\"招标原文短摘录\",\"source_page\":数字或null,\"source_clause_ids\":[\"评分条款ID\"],\"ocr_required\":false,\"scoring\":{\"max_score\":数字,\"kind\":\"boolean|manual\",\"items\":[{\"name\":\"叶子评分项\",\"max_score\":数字,\"criterion\":\"计分或扣分条件\"}]}}]}\n\n严格要求：不得使用 Markdown 或在 JSON 前后添加说明；不得逐条复述招标原文；同一底层审查事实的重复表述可合并，但会独立改变结论或分值的条款不得误合并。先排除依赖投后履行、采购平台状态、外部网站或原件核验、评审过程动作或其他非本次文件证据的事项；再排除已被具体子规则承接的“资料齐全、响应全部要求、否决情形汇总”等概括性规则。{{limits}}\n{{score_requirement}}\n只保留能通过已上传投标文件中的机器可读文字、表格、元数据或后续 OCR 核验的事项，规则必须明确且能据文件内容判断。请根据完整语境判断，不要输出密封与递交要求、响应文件份数或电子版要求、递交地点/时间、开标现场、线下原件、纸质材料、投标文件本身无法体现的签收事项，以及其他无法仅凭投标文件核验的事项。若规则的决定性证据需要识别扫描图片、证照图片、签章或手写内容，请将 ocr_required 设为 true；文字或表格已经足以判断的规则，即使附带材料可能为扫描件也设为 false；可独立判断的文字条件和图像条件应拆分。source_page 填写最直接依据所在页，无法确定时为 null。\n\n分类说明：qualification 为资格性；compliance 为符合性；substantive 为实质性；rejection 为无效投标/废标；objective 为客观分；subjective 为主观分。objective 和 subjective 必须填写 scoring.max_score，且只能填写招标原文明确规定的满分；没有明确满分时不要输出为评分项。objective 仅“满足即满分”时 kind 为 boolean，分档、数量、累计或人工判断评分时 kind 为 manual；subjective 的 kind 为 manual。存在多个有独立分值或扣分条件的叶子项时写入 scoring.items；没有明确叶子项时可省略 items。评分规则必须把对应覆盖清单中的评分条款 ID 原样写入 source_clause_ids；非评分项省略 source_clause_ids 和 scoring。\n\n评分条款覆盖清单：\n{{score_audit}}\n\n招标文件原文：\n{{text}}", "limits", "score_requirement", "score_audit", "text"),
    "extract_rules_continue_user": _template("评审规则提取 · 本地恢复后续提", "模型 JSON 尾部异常时，在已回收完整规则基础上只补充遗漏项。", "上一次提取的 JSON 在尾部异常；系统已从其中安全回收下列完整规则。请重新阅读当前原文，只补充尚未被已回收规则覆盖、且符合系统规则的独立审查点；不要复述、改写或重复已回收规则，不得猜测截断项。若没有遗漏，只返回 {\"rules\":[]}。\n\n只返回一个合法 JSON 对象：\n{\"rules\":[{\"category\":\"qualification|compliance|substantive|rejection|objective|subjective\",\"title\":\"简明规则名称\",\"check_rule\":\"面向投标文件的明确检查指令\",\"source_text\":\"招标原文短摘录\",\"source_page\":数字或null,\"source_clause_ids\":[\"评分条款ID\"],\"ocr_required\":false,\"scoring\":{\"max_score\":数字,\"kind\":\"boolean|manual\",\"items\":[{\"name\":\"叶子评分项\",\"max_score\":数字,\"criterion\":\"计分或扣分条件\"}]}}]}\n\n已回收规则：\n{{existing_rules}}\n\n当前招标文件原文：\n{{text}}", "existing_rules", "text"),
    "extract_rules_compile_user": _template("评审规则提取 · 规则编译", "将分段原始条款统一为无重复、可执行的当前规则集。", "请将以下原始评审条款编译为一套少而精、可直接审查电子投标文件的规范规则集。只返回 JSON：\n{\"rules\":[{\"category\":\"qualification|compliance|substantive|rejection|objective|subjective|other\",\"title\":\"简明规则名称\",\"check_rule\":\"完整、原子化、可执行的检查规则\",\"source_text\":\"最直接的招标原文依据\",\"source_page\":数字或null,\"source_clause_ids\":[\"评分条款ID\"],\"ocr_required\":false,\"scoring\":{\"max_score\":数字,\"kind\":\"boolean|manual\",\"items\":[{\"name\":\"叶子评分项\",\"max_score\":数字,\"criterion\":\"计分或扣分条件\"}]}}]}\n\n规则编译原则：1. 以“底层审查事实”而不是标题文字去重；同一材料的提交要求、凭证要求、资格判断和缺失后果必须合成一条规则，即使候选分属资格、符合、实质性或废标类别；同一响应字段的期限、地点、标准、金额、税费口径或证明要求应合并为一条最完整规则，并保留全部实质参数；2. 章节标题、资料包完整性、格式模板说明、概括性上位要求若已被具体子规则覆盖，必须删除，不得与子规则并存；3. 保留会独立改变不同结论或不同分值的事实，评分项不得与资格项误合并；4. 只保留可由当前电子投标文件本身核验的事项。删除纸质正副本标记及一致性、装订、密封、份数、递交、签收、线下原件；也删除投后合同签订、履约、履约保证金、采购数量调整，以及评审过程中才发生的澄清、补正、谈判、异常低价说明、算术更正、投诉等事项。串通、行贿、弄虚作假、失信、停业或破产等外部事实，除非规则仅核验投标文件中的书面声明，否则不生成单份文件审查规则；5. 对“前附表、星号、关键条款、采购需求、某章节”等交叉引用，只有候选中已含具体可核验条件时才保留，并把具体条件写入 check_rule；没有具体条件的笼统引用必须删除；6. 条件规则只在触发条件可从当前投标文件判断且触发后确需审查时保留；明显不适用的模板占位不生成独立风险项；7. 评分规则必须完整保留计分对象、有效期、证明材料、公式、每项分值与总分上限；层级评分表还必须列出父项总分、每个叶子模块/功能点、各自分值、评价维度及缺项/缺陷扣分和封顶规则，并在 scoring.items 中保留结构化叶子项；合并评分规则时必须合并保留全部 source_clause_ids，不得因标题相近丢掉独立计分条款；8. OCR 按决定性证据形态重新校准：证照、许可证、执照、身份证、签字盖章、手写内容、扫描凭证、保函、票据、截图等必须查看图像外观的规则设为 true；目录或提取出的名称不能代替图像核验；9. source_text 必须来自输入，source_page 取最直接依据页；10. 每个底层事实只输出一次，不得换标题重复，也不得把“不满足则无效”另拆成规则。不得编造或遗漏明确且有评审价值的条款。\n\n原始条款：\n{{candidates}}", "candidates"),
    "extract_rules_coverage_user": _template("评审规则提取 · 覆盖审计", "核验规范规则集是否遗漏招标文件中可由投标文件审查的条款。", "请依据原始条款和已编译规则做覆盖审计。只返回 JSON：\n{\"missing_rules\":[{\"category\":\"qualification|compliance|substantive|rejection|objective|subjective|other\",\"title\":\"简明规则名称\",\"check_rule\":\"完整检查规则\",\"source_text\":\"招标原文依据\",\"source_page\":数字或null,\"source_clause_ids\":[\"评分条款ID\"],\"ocr_required\":false,\"scoring\":{\"max_score\":数字,\"kind\":\"boolean|manual\",\"items\":[{\"name\":\"叶子评分项\",\"max_score\":数字,\"criterion\":\"计分或扣分条件\"}]}}]}\n\n只列出确实未被已编译规则覆盖、可通过当前电子投标文件文字或后续 OCR 核验、且会独立改变评审结论或分值的条款。审计覆盖时按底层事实判断：已有规则包含材料要求及缺失后果后，不得再把“提供凭证”“未提供则无效”、章节总标题、资料完整性或同义改写列为遗漏；同一响应字段的期限、地点、标准、金额等已被完整规则覆盖时，不得拆成新的遗漏项；纸质正副本、装订密封、递交签收、投后合同或履约、履约保证金、采购数量调整、澄清补正、谈判、异常低价说明、算术更正、投诉及其他评审过程事项也不是遗漏。串通、行贿、弄虚作假、失信或停业等外部事实，除非只要求核验书面声明，也不是单份投标文件审查的遗漏。评分项应特别核对业绩、报价、人员、资质、方案及总分上限，并逐个核对 source_clause_ids 是否已有最终规则承接。对层级评分表必须逐项审计：父项总分、每个服务模块/功能点、分档或每项分值、缺项和缺陷扣分、封顶规则，任一项未体现在 check_rule 和 scoring.items 中才视为遗漏；不得以“技术方案”“系统功能”等泛称替代具体评分维度。新增规则必须继承对应 source_clause_ids；决定性证据属于证照、签章、扫描凭证或其他图像外观时，ocr_required 必须为 true。没有遗漏时返回空数组。\n\n原始条款：{{candidates}}\n\n已编译规则：{{compiled_rules}}", "candidates", "compiled_rules"),
    "extract_rules_quality_gate_user": _template("评审规则提取 · 最终质量门控", "在保存前从完整规则集中剔除重复、不可执行或无评审价值的候选规则。", "请对全部候选规则做最后一次全局质量审计。只返回 JSON：\n{\"drops\":[{\"rule_id\":\"R1\",\"reason\":\"duplicate|not_file_verifiable|procedural|umbrella|not_scoring_rule|unsupported_cross_reference\",\"duplicate_of\":\"另一候选 ID、受保护规则名称或null\"}]}\n\n只列出应剔除的候选，不得改写规则、不得新增规则。受保护规则仅包括人工补充、人工修改过检查内容或评分口径的规则，以及已启用通用规则；上一次规则集的勾选或取消勾选状态不是本轮提取依据，也不得影响本轮候选取舍。受保护规则本身不能剔除；候选与其重复时，应剔除候选。按完整语义和底层审查事实判断：1. duplicate：同一材料的提供要求、凭证要求、资格判断和缺失后果，或同一响应字段的同义/拆分表达，已被信息更完整的候选或受保护规则覆盖；2. not_file_verifiable：无法从当前电子投标文件的文字、表格、元数据或后续 OCR 直接核验；需要 OCR 本身不是剔除理由；3. procedural：属于纸质正副本、装订密封、份数、递交签收，评审中的澄清补正、谈判、异常低价说明、算术更正、投诉，或中标后的合同签订、履约、履约保证金、采购数量调整；4. umbrella：章节总标题、资料包完整性、格式模板或被具体子规则完整覆盖的概括性要求；5. not_scoring_rule：被误列为评分项，但原文没有明确计分对象、计分条件或分值，例如成交供应商数量、流程结果、原件核验安排；6. unsupported_cross_reference：只引用前附表、星号、采购需求或某章节，却没有写明可核验的具体条件。\n\n必须保留会独立改变不同结论或不同分值的事实。凡具有明确评分对象、标准和满分的有效评分规则不得剔除；同一材料作为资格门槛和独立评分依据时两条均可保留。评分表中的业绩、报价、人员、资质、方案、分档、公式、叶子子项、缺项/缺陷扣分和封顶逻辑优先保留。证照、签章、扫描凭证等需要后续 OCR 的规则仍属于可核验规则。证据不足以确认应剔除时不要列入 drops；没有应剔除项时返回空数组。\n\n候选规则：{{candidates}}\n\n受保护规则：{{protected_rules}}", "candidates", "protected_rules"),
    "extract_rules_supplement_user": _template("评审规则提取 · 评分补充", "遗漏评分条款的补充提取。", "仅根据以下评分条款，补充主规则提取遗漏的明确评分项。只返回合法 JSON：\n{\"rules\":[{\"category\":\"objective|subjective\",\"title\":\"简明规则名称\",\"check_rule\":\"面向投标文件的明确检查指令\",\"source_text\":\"原文短摘录\",\"source_page\":数字或null,\"source_clause_ids\":[\"评分条款ID\"],\"ocr_required\":false,\"scoring\":{\"max_score\":数字,\"kind\":\"boolean|manual\",\"items\":[{\"name\":\"叶子评分项\",\"max_score\":数字,\"criterion\":\"计分或扣分条件\"}]}}]}\n\n已有评分规则：{{existing_rules}}\n必须仅返回缺失项，不得重复已有项；每个明确评分条款都要覆盖，并把条款标题中的评分条款 ID 原样写入 source_clause_ids。对于按多个服务模块或功能点累计得分的主观项，输出一条保留总分的规则，在 scoring.items 中逐项列明模块、每项分值和扣分逻辑，同时让 check_rule 保留完整可读口径，不能拆成无法核对总分的零散标题。objective 和 subjective 都必须有 scoring.max_score，且仅能填写原文明确的满分。决定性证明材料必须查看证照、签章、凭证或其他图片外观时，ocr_required 必须为 true；source_page 填写最直接依据页，无法确定时为 null。不得使用 Markdown 或添加说明；title 最多 30 字，普通 check_rule 尽量控制在 320 字内，但不得删减叶子评分项；source_text 最多 180 字。\n\n评分条款：\n{{packet_text}}", "existing_rules", "packet_text"),
    "review_documents": _template("单项文件审查 · 系统", "兼容单项审查流程的角色和边界。", "你是招投标电子文件审查助手。所有结果均由人工审核，应逐项引用可见原文并积极给出最可能的响应判断、疑点和风险。必须区分投标人自主方案、响应承诺/偏离表、招标文件复述/表格模板和无法判断的材料：前两类可分别支持响应判断，但招标文件复述或空表不能单独证明投标人的技术能力或主观评分。对于证照、许可证、执照、签字盖章、扫描凭证等必须看图像外观才能确认的事实，当前没有实际 OCR 结果时只能标记 ocr_required，风险为低；不得因文本未提取到就判为不满足或高风险。可以提出暂定推断，但不得编造图片、签字、盖章或线下材料。"),
    "review_documents_user": _template("单项文件审查 · 任务", "规则、投标文件及 JSON 输出要求。", "请逐条审查投标文件。返回 JSON：\n{\"results\":[{\"rule_id\":\"规则ID\",\"status\":\"satisfied|not_satisfied|partial|not_found|manual|ocr_required\",\"evidence\":\"投标文件原文摘录\",\"page_hint\":\"页码或null\",\"reason\":\"简洁判断理由\",\"risk_level\":\"low|medium|high\",\"confidence\":\"high|medium|low\",\"evidence_quality\":\"sufficient|limited|missing\"}]}\n\n必须按输入顺序覆盖每个 rule_id，且每个 ID 恰好返回一次，不得新增 ID。page_hint 填写最直接证据页，无法确定时为 null；evidence 只摘录原文，不重复页码。审查结果不得自行给分或写评分建议。对于 ocr_required=true 的规则，当前系统未执行 OCR；若关键证据仅存在于图片、签章、证照或手写内容，必须返回 ocr_required 和 low 风险，不能据此返回不满足。\n规则：\n{{rules}}\n\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n原文：\n{{text}}", "rules", "document_name", "bidder_name", "text"),
    "score_objective": _template("客观分辅助评分 · 系统", "兼容客观评分流程的角色与边界。", "你是招投标客观评分辅助助手。应依据评分规则和投标文件原文积极提取证据并给出明确的 AI 建议分。允许提出疑点和暂定判断，所有结果均由人工复核；不得编造原文、页码或材料，不得超出评分上限。"),
    "score_objective_user": _template("客观分辅助评分 · 任务", "客观评分规则、投标文件及 JSON 输出要求。", "返回 JSON：{\"results\":[{\"rule_id\":\"规则ID\",\"met\":true|false|null,\"suggested_score\":数字或null,\"matched_count\":数字或null,\"needs_ocr\":true|false,\"evidence_items\":[{\"name\":\"证据名称\",\"page_hint\":\"页码\",\"validity\":\"valid|uncertain|invalid\",\"reason\":\"逐项理由\"}],\"evidence\":\"原文摘录\",\"calculation\":\"计分过程\",\"reason\":\"判断理由\",\"confidence\":\"high|medium|low\"}]}。必须按输入顺序覆盖每个 rule_id，且每个 ID 恰好返回一次，不得新增 ID。满足即满分项可同时返回 met；数量、累计、分档等规则必须尽量给出 matched_count、计算过程和 suggested_score。证据不完全或需要 OCR 时仍应根据可见材料给出暂定建议分，并将 needs_ocr 设为 true，不要仅因需要人工复核而留空。不得超过 scoring.max_score。\n评分规则：{{rules}}\n投标文件：{{document_name}}\n全文或证据包：\n{{text}}", "rules", "document_name", "text"),
    "score_subjective": _template("主观分辅助评分 · 系统", "兼容主观评分流程的角色与边界。", "你是招投标主观评分辅助助手。应依据评分规则和投标文件原文给出有证据支撑的评分建议。多子项评分必须逐项核对后再汇总；招标文件复述、偏离表的“无偏离”和空泛承诺不能单独作为技术先进性、完整性或可靠性的得分证据。只能依据评分规则与投标文件原文，不得编造材料或超出评分上限。"),
    "score_subjective_user": _template("主观分辅助评分 · 任务", "主观评分规则、投标文件及 JSON 输出要求。", "返回 JSON：{\"results\":[{\"rule_id\":\"规则ID\",\"suggested_score\":数字,\"needs_ocr\":true|false,\"evidence_items\":[{\"name\":\"评分子项或模块\",\"page_hint\":\"页码\",\"validity\":\"valid|uncertain|invalid\",\"reason\":\"该子项的投标人自主方案证据或缺口\"}],\"evidence\":\"最关键原文摘录\",\"calculation\":\"子项分值、缺项或缺陷扣分及汇总\",\"reason\":\"得扣分理由\",\"confidence\":\"high|medium|low\"}]}。必须按输入顺序覆盖每个 rule_id，且每个 ID 恰好返回一次，不得新增 ID。分数不得超出规则 scoring.max_score。对含多个服务模块、功能点或分档的规则，evidence_items 必须逐项列出已核验模块及缺项，calculation 必须说明汇总，不得只给总分。仅招标文件复述、偏离表“无偏离”、目录或空泛承诺时，validity 为 uncertain，不得作为技术先进性正向得分证据。证据不完全或需要 OCR 时仍应依据可见材料给出暂定建议分，并用 needs_ocr 标记核验需要；不得编造证据。\n评分规则：{{rules}}\n投标文件：{{document_name}}\n原文：\n{{text}}", "rules", "document_name", "text"),
    "evaluate_all": _template("综合评审 · 系统", "综合评审的角色与边界。", "你是招投标综合评审辅助助手。准确发现问题和完整提出建议优先于节省输出。所有结果均由人工最终审核，因此应积极给出最可能的结论、风险、证据、理由和建议分，可明确提出疑点与暂定推断；但必须严格区分投标人自主设计、响应承诺/偏离表、招标文件复述或表格模板和 AI 推断。招标文件复述只能证明其出现于投标文件，不能单独证明技术能力、方案先进性或主观评分。需要查看证照、许可证、执照、签字盖章、扫描凭证等图像外观的规则，在没有实际 OCR 结果时必须输出 ocr_required 和低风险，不得把文本未命中当成材料缺失或高风险。不得编造原文、页码、签章或线下材料。"),
    "evaluate_all_guidance": _template("综合评审 · 通用业务指令", "独立于任务模板的综合评审判断原则；用于持续完善检查方式。", "应基于全文覆盖扫描和直接原文，主动提出最可能的审查结论、证据、理由和评分建议。证据不完整时可以给出暂定建议、说明缺口和核验重点；不要仅因最终需要人工审核而回避判断或把普通问题一律转为人工核验。OCR 只用于决定性事实必须查看图片外观的情形，例如证照/许可证/执照的内容与有效性、签字盖章、手写内容、扫描缴款凭证、保函票据或截图；若规则标记 ocr_required=true 且当前没有实际 OCR 结果，必须标明待识别对象并以低风险处理，不得因目录或文本层未命中而认定材料缺失或高风险。反之，普通文字缺失、交叉引用或一般人工复核不得冒充 OCR。项目范围偏离应从主体、技术、设备、标准、服务对象、交付物、时间地点等完整语境判断，不使用固定地区、项目名或设备词表作结论。"),
    "evaluate_all_output_contract": _template("综合评审 · 结果结构通用约束", "所有综合评审子流程共享的 JSON 与结果去重约束；通常无需修改。", "只返回一个完整 JSON 对象，不使用 Markdown 或前后说明；关闭每个数组和对象。文本字段引用引号时使用中文引号，不得出现未转义英文双引号或字段内换行。证据、计分过程和理由只写投标文件事实、判断与计算，不复述规则标题、检查规则或招标原文要求；同一事实只写一次。"),
    "evaluate_all_scope_profile": _template("综合评审 · 项目范围画像 · 系统", "从招标文件建立全项目一致性审查基准。", "你是招投标项目范围分析助手。只能根据招标文件、已确认规则及项目名称归纳明确的项目范围；不要猜测未出现的限制，不要评价投标文件，也不要把潜在问题写成既成事实。"),
    "evaluate_all_scope_profile_user": _template("综合评审 · 项目范围画像 · 任务", "在综合评审前一次性建立项目主体、技术、设备和交付范围的紧凑基准。", "请只返回合法 JSON：{\"project_identity\":\"项目主体、采购对象和目标的简洁描述\",\"scope_summary\":\"工作范围摘要\",\"service_targets\":[\"服务对象或应用场景\"],\"core_tasks\":[\"核心任务\"],\"technical_topics\":[\"技术主题或方法\"],\"equipment_or_materials\":[\"明确要求或相关的设备/材料类别\"],\"deliverables\":[\"成果或交付物\"],\"standards_or_rules\":[\"适用标准、法规或规范\"],\"regions\":[\"实施地域\"],\"keywords\":[\"有区分度的项目词\"]}。只归纳本项目具有约束力的采购范围和要求；不要把示例、格式模板、投标人资格经历、引用案例或允许的可选方案误当成本项目唯一范围。字段可为空数组或空字符串，不要为了填满字段补造信息。\n项目名称：{{project_name}}\n已确认规则：{{rules}}\n招标文件依据：\n{{tender_text}}", "project_name", "rules", "tender_text"),
    "json_repair": _template("结构化结果修复 · 系统", "仅修复模型已经生成的 JSON 语法，不重新进行业务判断。", "你是 JSON 结构修复器。只修复给定响应中的语法、转义、括号和顶层结构；保留已有字段和值，不新增业务事实，不解释，不输出 Markdown。"),
    "json_repair_user": _template("结构化结果修复 · 任务", "格式异常时只回传模型响应本身，避免重新发送整份投标文件。", "请把下列模型响应修复为一个可解析的 JSON 对象。预期顶层字段：{{expected_field}}。只输出修复后的 JSON；不得补造响应中不存在的证据、分数或结论。\n\n待修复响应：\n{{raw_response}}", "expected_field", "raw_response"),
    "evaluate_all_full_scan_user": _template("综合评审 · 全文证据扫描", "每个连续页块只扫描一次，同时建立规则证据和项目范围偏离候选。", "{{retry_note}}这是投标文件全文证据扫描的一部分。完成两类独立工作：一、将当前页块与规则目录逐项对照，返回规则证据；二、将当前页块与项目范围画像对照，发现任何可能与本项目不一致的主体、地域、技术主题、设备/材料、标准法规、服务对象、成果交付、时间地点或其他内容。对技术/主观评分，必须区分投标人自主方案、响应承诺或偏离表、招标文件复述/表格模板；只有自主方案可直接支持能力或得分，承诺只能支持响应性，复述/模板不能单独支持得分。范围偏离只报告可复核候选，不作废标或最终结论；外地业绩、注册地址、公司介绍、合理引用和可选方案不应仅因不同而认定异常。\n只返回合法 JSON：{\"matches\":[[\"规则ID\",\"页码\",\"原文短摘录\",\"supports|contradicts|partial|suspected\",\"high|medium|low\",\"bidder_design|bidder_commitment|tender_quote|form_template|unknown\"]],\"scope_anomalies\":[[\"页码\",\"开放类型描述\",\"high|medium|low\",\"原文短摘录\",\"与项目范围的关系或疑点\"]]}。matches 每个数组恰好六项、最多36条；普通规则同一页块最多保留一条，含多个服务模块或子项的评分规则每个子项最多一条、同一规则最多三条；重复内容不要重复返回。第六项为证据性质，必须如实标注；第五项表示该摘录对本规则最终判断的直接性和诊断价值，不表示风险。scope_anomalies 每个数组恰好五项、最多8条；原文短摘录最多60字，关系或疑点最多50字。范围候选只写原文与范围的直接关系，不写重复解释。没有候选时对应数组返回空数组。不得输出 Markdown、说明文字、编造页码或原文。\n项目范围画像：{{project_scope}}\n规则目录：{{rules}}\n投标文件：{{document_name}}；投标人：{{bidder_name}}；当前范围：{{chunk_label}}\n当前连续页块：\n{{text}}", "retry_note", "project_scope", "rules", "document_name", "bidder_name", "chunk_label", "text"),
    "evaluate_all_review_user": _template("综合评审 · 审查规则组", "综合评审中资格、符合、实质性/废标规则组的任务提示词。", "{{retry_note}}请根据全文覆盖扫描候选、项目范围画像、范围偏离候选、重点原文和规则要求逐条给出明确的 AI 审查建议，只返回 JSON：\n{\"results\":[{\"rule_id\":\"规则ID\",\"status\":\"satisfied|not_satisfied|partial|not_found|manual|ocr_required\",\"evidence\":\"投标文件原文摘录\",\"page_hint\":\"页码或null\",\"reason\":\"判断理由；可列出疑点和推断\",\"risk_level\":\"low|medium|high\",\"confidence\":\"high|medium|low\",\"evidence_quality\":\"sufficient|limited|missing\"}]}\n必须按输入顺序覆盖每个 rule_id，且每个 ID 恰好返回一次，不得新增 ID；本组只输出审查结论和风险，不得自行给分或写评分建议。page_hint 填写最直接证据页，无法确定时为 null；每条 evidence 只保留最直接的原文，最多180字，不重复页码；reason 只写“事实→规则→建议”的一句话，最多120字。全文扫描未报告候选时，也应给出“全文扫描未发现相应异常/证据”的最可能建议，不要默认转为人工核验。对技术能力、方案完整性或性能要求，必须写明证据是投标人自主方案、响应承诺还是招标文件复述；仅复述/模板不能作为正向技术能力证据。范围偏离候选可能涉及任何不属于本项目的主体、技术、设备、标准、服务对象、交付物、时间地点或其他内容；它们只是线索，必须结合原页、项目范围和规则判断，不得把合理业绩、地址、公司介绍或引用材料直接认定为异常。若规则 ocr_required=true 且当前证据包没有实际 OCR 结果，status 必须为 ocr_required，risk_level 必须为 low，reason 写明待识别的证照、签章、凭证或图片字段；目录存在、文本未命中或只有证件名称都不能据此判定满足、部分满足、不满足或高风险。只有关键事实完全可由机器可读文字核验时才作普通结论；一般人工复核才使用 manual。不得编造原文、图片内容或签章状态。\n规则组：{{rules}}\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n全文扫描证据包、项目范围画像与重点原文：\n{{text}}", "retry_note", "rules", "document_name", "bidder_name", "text"),
    "evaluate_all_objective_user": _template("综合评审 · 客观评分规则组", "综合评审中客观评分规则组的任务提示词。", "{{retry_note}}请根据全文覆盖扫描候选、重点原文和评分规则给出明确的 AI 建议分，只返回 JSON：\n{\"results\":[{\"rule_id\":\"规则ID\",\"met\":true|false|null,\"suggested_score\":数字或null,\"matched_count\":数字或null,\"needs_ocr\":true|false,\"evidence_items\":[{\"name\":\"项目或证据名称\",\"page_hint\":\"页码\",\"validity\":\"valid|uncertain|invalid\",\"reason\":\"逐项判断\"}],\"evidence\":\"原文摘录\",\"calculation\":\"计分过程\",\"reason\":\"判断理由\",\"confidence\":\"high|medium|low\"}]}\n必须按输入顺序覆盖每个 rule_id，且每个 ID 恰好返回一次，不得新增 ID。满足即满分项可返回 met；数量、累计、分档规则必须尽量返回 matched_count、逐项证据、计算过程和 suggested_score。逐项 reason、calculation 与总 reason 均只保留必要事实和计算关系，不重复解释；evidence 最多180字、总 reason 最多120字。证据来源为招标文件复述、目录、空表或仅“无偏离”承诺时，只能标记 uncertain，不能作为已满足客观条件的直接证据。全文扫描未发现相关材料时也应根据评分规则给出最可能的建议（通常为0分）并说明依据。需要 OCR 或证据不完全时仍应给出暂定建议分并标记 needs_ocr，不得仅因需要人工审核而留空；不得超过 scoring.max_score，不得编造证据。\n评分规则组：{{rules}}\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n全文扫描证据包与重点原文：\n{{text}}", "retry_note", "rules", "document_name", "bidder_name", "text"),
    "evaluate_all_subjective_user": _template("综合评审 · 主观评分规则组", "综合评审中主观评分规则组的任务提示词。", "{{retry_note}}请根据全文覆盖扫描候选、重点章节和评分规则大胆给出有依据的评分建议，只返回 JSON：\n{\"results\":[{\"rule_id\":\"规则ID\",\"suggested_score\":数字,\"needs_ocr\":true|false,\"evidence_items\":[{\"name\":\"评分子项或服务模块\",\"page_hint\":\"页码\",\"validity\":\"valid|uncertain|invalid\",\"reason\":\"自主方案证据、缺项或缺陷\"}],\"evidence\":\"最关键原文摘录\",\"calculation\":\"逐项分值、缺项/缺陷扣分和最终汇总\",\"reason\":\"得扣分理由及疑点\",\"confidence\":\"high|medium|low\"}]}\n必须按输入顺序覆盖每个 rule_id，且每个 ID 恰好返回一次，不得新增 ID。每条 evidence 仅保留最关键原文和页码，最多180字。对含多个模块、性能项、服务项或分档的评分规则，evidence_items 必须逐项覆盖招标评分项：写清已覆盖项、缺失项、发现的缺陷及其页码；calculation 必须按招标文件的“每项分值、每处扣分、总分上限”汇总，不能只给结论分。投标人自主方案才可作为技术能力、功能先进性、性能或可维护性的正向证据；偏离表“无偏离”、目录、招标文件逐字复述或空泛承诺最多证明响应态度，必须标记 uncertain，不能直接获得对应子项分。所有结果均由人工审核；证据不完整或需要 OCR 时仍应根据可见材料给出暂定分并说明核验点，不要仅因不确定而留空。建议分不得超过 scoring.max_score，不得编造证据。\n评分规则组：{{rules}}\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n全文扫描证据包与重点原文：\n{{text}}", "retry_note", "rules", "document_name", "bidder_name", "text"),
    "evaluate_all_cross_bid_price_user": _template("综合评审 · 跨投标人价格评分", "需要比较全部投标报价时，在单份文件评审后统一计算价格分。", "请依据评分规则，同时比较全部投标人的报价证据并给出 AI 建议分。只返回 JSON：\n{\"results\":[{\"document_id\":\"文件ID\",\"rule_id\":\"规则ID\",\"quoted_price\":数字或null,\"suggested_score\":数字或null,\"evidence\":\"报价原文及页码\",\"calculation\":\"基准价和计分过程\",\"reason\":\"判断理由\",\"confidence\":\"high|medium|low\"}]}\n必须覆盖每个文件和每条规则；先核对币种、报价口径、最高限价及异常报价，再按原规则计算。所有结果由人工审核，可给出明确的暂定分和疑点，但不得编造报价或超出 scoring.max_score。\n价格评分规则：{{rules}}\n全部投标人报价证据包：\n{{documents}}", "rules", "documents"),
    "evaluate_all_user": _template("综合评审 · 任务", "兼容综合审查、评分及 JSON 输出要求。", "{{retry_note}}对同一份投标文件完成下列三类工作，并只返回一个合法 JSON 对象：\n{\"review_results\":[{\"rule_id\":\"规则ID\",\"status\":\"satisfied|not_satisfied|partial|not_found|manual|ocr_required\",\"evidence\":\"原文摘录\",\"page_hint\":null,\"reason\":\"理由与疑点\",\"risk_level\":\"low|medium|high\",\"confidence\":\"high|medium|low\",\"evidence_quality\":\"sufficient|limited|missing\"}],\"objective_scores\":[{\"rule_id\":\"规则ID\",\"met\":true|false|null,\"suggested_score\":数字或null,\"matched_count\":数字或null,\"needs_ocr\":true|false,\"evidence\":\"原文摘录\",\"calculation\":\"计分过程\",\"reason\":\"判断理由\",\"confidence\":\"high|medium|low\"}],\"subjective_scores\":[{\"rule_id\":\"规则ID\",\"suggested_score\":数字,\"needs_ocr\":true|false,\"evidence\":\"原文摘录\",\"reason\":\"得扣分理由\",\"confidence\":\"high|medium|low\"}]}\n\n严格要求：不得使用 Markdown 代码块、不得在 JSON 前后添加说明、所有字符串必须使用标准 JSON 双引号和转义。{{limits}}\n审查规则：{{review_rules}}\n客观评分规则：{{objective_rules}}\n主观评分规则：{{subjective_rules}}\n所有结果均由人工审核，应积极给出最可能的判断、疑点和建议分。需要 OCR 或证据不完整时仍可基于可见材料给暂定建议并明确核验点；不得编造证据，评分不得超过 scoring.max_score。\n投标文件：{{document_name}}；投标人：{{bidder_name}}\n原文：\n{{text}}", "retry_note", "limits", "review_rules", "objective_rules", "subjective_rules", "document_name", "bidder_name", "text"),
}


